const input = $json.body ?? $json;

const lead = { ...input };
const errors = [];

const isEmpty = (v) =>
  v === undefined || v === null || String(v).trim() === '';

const allowedTags = [
  'hot',
  'warm',
  'future',
  'feedback only',
  'voicemail',
  'wrong contact',
  'not interested',
  'do-not-call',
];

// Normalize final_tag
lead.final_tag = String(lead.final_tag || '').trim().toLowerCase();

// Required: customer_name OR business_name
if (isEmpty(lead.customer_name) && isEmpty(lead.business_name)) {
  errors.push('At least one identifier is required (customer_name or business_name)');
}

// Required: phone OR email
if (isEmpty(lead.phone) && isEmpty(lead.email)) {
  errors.push('At least one contact method is required (phone or email)');
}

// Required individual fields
const requiredFields = [
  'call_outcome',
  'final_tag',
  'short_call_summary',
  'next_action',
];

for (const field of requiredFields) {
  if (isEmpty(lead[field])) {
    errors.push(`${field} is missing`);
  }
}

// Validate final_tag
if (lead.final_tag && !allowedTags.includes(lead.final_tag)) {
  errors.push(`final_tag must be one of: ${allowedTags.join(', ')}`);
}

// Add metadata
lead.received_at = lead.received_at || new Date().toISOString();
lead.lead_id = lead.lead_id || `${Date.now()}`;
lead.is_valid = errors.length === 0;
lead.validation_errors = errors;
lead.raw_payload = JSON.stringify(input);

return [{ json: lead }];
